#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    vector<int> queue;
    void push(int x) { queue.push_back(x); }
    int pop() {
        if (queue.empty()) {
            return -1; // handle empty queue correctly
        }
        int front = queue.front();
        queue.erase(queue.begin());
        return front;
    }
};

